final:
module register (
        input clk,
        input rst,
        input [3:0] d,
        output reg [3:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= d;
    end

endmodule
